import{_ as r,o as t,c as s,j as e,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"成长之钥","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/成长之钥.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/成长之钥.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/成长之钥.md"};function l(_,a,i,p,c,h){return t(),s("div",null,[...a[0]||(a[0]=[e("h1",{id:"成长之钥",tabindex:"-1"},[n("成长之钥 "),e("a",{class:"header-anchor",href:"#成长之钥","aria-label":'Permalink to "成长之钥"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),o('<h1 id="成长之钥-1" tabindex="-1">成长之钥 <a class="header-anchor" href="#成长之钥-1" aria-label="Permalink to &quot;成长之钥&quot;">​</a></h1><p>成长之钥<br> D+500<br> 魔幻本质<br> 这是一把微闪着银光的密钥，大约有25厘米长，在它接触到一柄武器/法器后（无论其为何材质），便会永久融入其中，无法再取出。特殊的，如果st允许，这柄神秘的钥匙也可以用于概念武装<br> 获得成长之钥加持的武器获得等于人物支线等级对应级别的武器模板，这会令武器伤害/法术强度提升至（不包括附加）（D6C11B18A27S38）点<br> 若是仅提供附加成功的武器，则武器提供的附加成功会提升至（D2/C4/B7/A12/S16)点<br> 若附加的武器被其他能力所提升了武器伤害、法术强度、附加成功，成长之钥的提升会在这些能力提升之后再进行结算。若武器同时具有法术强度、武器伤害、附加成功，仅提升数值较高（1点附加成功按照2点武器伤害/法术强度计算）的那一项。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
